B.aLd=s([B.f1,B.eq,B.iB,B.f2],A.a7("p<mb>"))
B.R7=new A.cL("Grundsatz","Einen allgemeinen gesetzlichen Anspruch auf eine Abfindung gibt es in Deutschland nicht. Eine Abfindung ist meist das Ergebnis einer Einigung \u2013 etwa in einem Vergleich vor dem Arbeitsgericht oder in einem Aufhebungsvertrag.")
B.QJ=new A.cL("Die wichtigsten Ausnahmen","Ein Anspruch kann sich ergeben aus einem Abfindungsangebot bei betriebsbedingter K\xfcndigung (\xa7 1a KSchG), aus einem Sozialplan (\xa7\xa7 112, 112a BetrVG), aus einem Nachteilsausgleich (\xa7 113 BetrVG) oder aus einem gerichtlichen Aufl\xf6sungsurteil (\xa7\xa7 9, 10 KSchG).")
B.QF=new A.cL("Warum trotzdem oft gezahlt wird","Auch ohne Anspruch bieten viele Arbeitgeber eine Abfindung an, um das Kosten- und Prozessrisiko einer K\xfcndigungsschutzklage zu vermeiden. Genau darin liegt der Verhandlungsspielraum.")
B.aIv=s([B.R7,B.QJ,B.QF],t.aX)
B.aLb=s(["\xa7 1a KSchG","\xa7\xa7 9, 10 KSchG","\xa7\xa7 112, 112a, 113 BetrVG"],t.s)
B.Rg=new A.hH(B.ie,"Habe ich Anspruch auf eine Abfindung?","Meistens nein \u2013 aber es gibt wichtige Ausnahmen und viel Verhandlungsspielraum.",B.aIv,B.aLb)
B.QN=new A.cL("Die Faustformel","Als grobe Orientierung gilt: ein halbes Bruttomonatsgehalt je Jahr der Betriebszugeh\xf6rigkeit. Diese Gr\xf6\xdfe nennt auch \xa7 1a KSchG als Regelabfindung. Sie ist ein Anhaltspunkt, keine Obergrenze und kein Anspruch.")
B.QD=new A.cL("Was die H\xf6he beeinflusst","Wie gut die Erfolgsaussichten einer K\xfcndigungsschutzklage sind, wie dringend der Arbeitgeber die Trennung braucht, die Dauer der Betriebszugeh\xf6rigkeit und die Lage am Arbeitsmarkt wirken sich auf die tats\xe4chliche H\xf6he aus.")
B.QI=new A.cL("Mehr als nur Geld","Verhandelbar sind neben dem Betrag oft auch die Zeugnisnote, eine bezahlte Freistellung, der Verzicht auf R\xfcckzahlungsklauseln, der Auszahlungszeitpunkt (steuerlich relevant) und Leistungen wie Outplacement.")
B.aOV=s([B.QN,B.QD,B.QI],t.aX)
B.aMF=s(["\xa7 1a KSchG"],t.s)
B.R8=new A.hH(B.ie,"Wie hoch f\xe4llt eine Abfindung \xfcblicherweise aus?","Die Faustformel als Orientierung \u2013 und warum sie nur ein Startpunkt ist.",B.aOV,B.aMF)
B.R_=new A.cL("Prozessrisiko als Druckmittel","Eine fristgerechte K\xfcndigungsschutzklage h\xe4lt den Rechtsweg offen. F\xfcr den Arbeitgeber bedeutet ein laufendes Verfahren Unsicherheit, Zeit und Kosten \u2013 das erh\xf6ht die Bereitschaft, sich per Vergleich zu einigen.")
B.R0=new A.cL("Auszahlung ins Folgejahr","Der Zeitpunkt der Auszahlung kann die Steuerlast ver\xe4ndern (Progression, F\xfcnftelregelung). Ob sich eine Verschiebung lohnt, l\xe4sst sich im Rechner dieser App durchspielen.")
B.QR=new A.cL("Nicht unter Druck unterschreiben","F\xfcr einen Aufhebungsvertrag gibt es keine gesetzliche Bedenkzeit und kein Widerrufsrecht. Einmal unterschrieben, gilt er \u2013 deshalb ist Ruhe vor der Unterschrift wichtiger als Tempo.")
B.aEW=s([B.R_,B.R0,B.QR],t.aX)
B.aMH=s(["\xa7 34 EStG","\xa7 4 KSchG"],t.s)
B.Rf=new A.hH(B.ie,"Verhandlungshebel bei Abfindung und Aufhebung","Prozessrisiko, Fristen und Timing sind deine st\xe4rksten Argumente.",B.aEW,B.aMH)
B.QP=new A.cL("Vertrauen \u2192 Interdependenz","Vertrauen ist subjektiv und braucht Zeit; es garantiert keine Gegenleistung. Wirksamer ist es, die Anreize zu koppeln: Wenn beide Seiten erkennen, dass Zusammenarbeit im eigenen Interesse liegt, tr\xe4gt die Einigung von selbst.")
B.QV=new A.cL("Zuh\xf6ren \u2192 proaktiv fragen","Blo\xdfes (auch aktives) Zuh\xf6ren ist reaktiv. Wer die Verhandlung f\xfchren will, stellt zuerst Fragen und lenkt so das Gespr\xe4ch dorthin, wo am meisten zu lernen ist.")
B.R4=new A.cL("Transparent \u2192 durchscheinend auf der Sache","Bei Beziehung und Kommunikation darfst du offen sein. Auf der Sachebene gilt: nur so viel preisgeben, wie n\xf6tig ist, damit die Gegenseite eine Einigung anstrebt \u2013 nicht mehr.")
B.QC=new A.cL("Nett & fair \u2192 positiv und vern\xfcnftig",'Nettigkeit kann als Schw\xe4che gelesen werden. Sei stattdessen positiv, aber nicht naiv, und statt \u201esubjektiv fair" lieber \u201evern\xfcnftig": ein Vorschlag, der im Wertesystem beider Seiten nachvollziehbar ist.')
B.QG=new A.cL("Treu zur Person \u2192 treu zum Prozess","Bleib dem fairen Verhandlungsprozess verpflichtet, nicht bedingungslos der Gegenseite. Und verpflichte dich dem guten Prozess \u2013 nicht einem bestimmten Ergebnis, das du ohnehin nicht garantieren kannst.")
B.QK=new A.cL("Das eigentliche Werkzeug: bewusster Machtverzicht",'Auf Machtspiele zu verzichten ist keine Schw\xe4che, sondern eine strategische Entscheidung, die oft zu besseren Ergebnissen f\xfchrt. (Nach \u201eGetting to Yes" von Fisher/Ury.)')
B.aLD=s([B.QP,B.QV,B.R4,B.QC,B.QG,B.QK],t.aX)
B.aOz=s(["Getting to Yes (Fisher/Ury)"],t.s)
B.Rh=new A.hH(B.ie,"Sieben Mythen der Win-win-Verhandlung","Nett, fair und vertrauensvoll allein macht dich in der Verhandlung nicht stark \u2013 hier die wirksameren Strategien.",B.aLD,B.aOz)
B.QL=new A.cL("Zwei Voraussetzungen","Das K\xfcndigungsschutzgesetz (KSchG) gilt, wenn das Arbeitsverh\xe4ltnis l\xe4nger als sechs Monate bestanden hat und im Betrieb in der Regel mehr als zehn Arbeitnehmer besch\xe4ftigt sind (Kleinbetriebsklausel).")
B.QH=new A.cL("Wenn es greift","Dann braucht eine ordentliche K\xfcndigung einen anerkannten Grund \u2013 betriebsbedingt, verhaltensbedingt oder personenbedingt \u2013 und muss sozial gerechtfertigt sein.")
B.QU=new A.cL("Auch im Kleinbetrieb","Selbst ohne KSchG darf eine K\xfcndigung nicht sitten- oder treuwidrig sein, und es gelten Formvorschriften, Fristen und der Sonderk\xfcndigungsschutz.")
B.aMC=s([B.QL,B.QH,B.QU],t.aX)
B.ayC=s(["\xa7 1 KSchG","\xa7 23 KSchG"],t.s)
B.Rc=new A.hH(B.kg,"Gilt der K\xfcndigungsschutz f\xfcr mich?","Das K\xfcndigungsschutzgesetz greift erst ab bestimmten Voraussetzungen.",B.aMC,B.ayC)
B.R5=new A.cL("Nur schriftlich","Eine K\xfcndigung muss schriftlich mit eigenh\xe4ndiger Unterschrift erfolgen (\xa7 623 BGB). Eine K\xfcndigung per E-Mail, SMS oder Messenger ist unwirksam.")
B.QZ=new A.cL("Betriebsrat anh\xf6ren","Gibt es einen Betriebsrat, muss er vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG). Ohne ordnungsgem\xe4\xdfe Anh\xf6rung ist die K\xfcndigung unwirksam.")
B.R3=new A.cL("K\xfcndigungsfristen","Die gesetzlichen Fristen richten sich nach \xa7 622 BGB und verl\xe4ngern sich f\xfcr Arbeitgeberk\xfcndigungen mit der Dauer der Betriebszugeh\xf6rigkeit. Im Vertrag oder Tarifvertrag k\xf6nnen abweichende Fristen stehen.")
B.aLg=s([B.R5,B.QZ,B.R3],t.aX)
B.aMO=s(["\xa7 623 BGB","\xa7 622 BGB","\xa7 102 BetrVG"],t.s)
B.Rb=new A.hH(B.kg,"Formfehler und Fristen: Wann eine K\xfcndigung unwirksam ist","Schriftform, Unterschrift, Betriebsratsanh\xf6rung \u2013 Formfehler z\xe4hlen.",B.aLg,B.aMO)
B.QM=new A.cL("Drei Wochen ab Zugang","Wer sich gegen eine K\xfcndigung wehren will, muss innerhalb von drei Wochen ab Zugang der schriftlichen K\xfcndigung K\xfcndigungsschutzklage beim Arbeitsgericht erheben (\xa7 4 KSchG).")
B.QQ=new A.cL("Was nach Fristablauf passiert","Wird die Frist vers\xe4umt, gilt die K\xfcndigung grunds\xe4tzlich als von Anfang an wirksam (\xa7 7 KSchG) \u2013 unabh\xe4ngig davon, ob sie eigentlich angreifbar gewesen w\xe4re.")
B.QX=new A.cL("Auch als Verhandlungsweg","Die Klage dient nicht nur der Weiterbesch\xe4ftigung. Viele Verfahren enden mit einem Vergleich, in dem eine Abfindung vereinbart wird.")
B.a04=s([B.QM,B.QQ,B.QX],t.aX)
B.aJ7=s(["\xa7 4 KSchG","\xa7 7 KSchG"],t.s)
B.Re=new A.hH(B.kg,"Die 3-Wochen-Frist f\xfcr die K\xfcndigungsschutzklage","Der wichtigste Termin \xfcberhaupt \u2013 nach Ablauf gilt die K\xfcndigung als wirksam.",B.a04,B.aJ7)
B.QW=new A.cL("Wann melden?","Wer wei\xdf, dass sein Arbeitsverh\xe4ltnis endet, muss sich sp\xe4testens drei Monate vor dem Ende arbeitsuchend melden. Liegen zwischen Kenntnis und Ende weniger als drei Monate, muss die Meldung innerhalb von drei Tagen nach Kenntnis erfolgen (\xa7 38 SGB III).")
B.QS=new A.cL("Wie melden?","Die Arbeitsuchendmeldung ist telefonisch, pers\xf6nlich oder online \xfcber die Website der Bundesagentur f\xfcr Arbeit m\xf6glich. Sie ist etwas anderes als die sp\xe4tere Arbeitslosmeldung.")
B.QT=new A.cL("Warum das wichtig ist","Eine versp\xe4tete Meldung kann als Meldevers\xe4umnis eine Sperrzeit nach sich ziehen (\xa7 159 SGB III) und damit den ALG-Bezug verk\xfcrzen.")
B.aLM=s([B.QW,B.QS,B.QT],t.aX)
B.aob=s(["\xa7 38 SGB III","\xa7 159 SGB III"],t.s)
B.Rd=new A.hH(B.kh,"Arbeitsuchend melden \u2013 so fr\xfch wie m\xf6glich","Vers\xe4umnis kann eine Sperrzeit ausl\xf6sen. Die Meldung geht auch online.",B.aLM,B.aob)
B.QE=new A.cL("ALG 1: Versicherungsleistung","Arbeitslosengeld 1 ist eine Leistung der Arbeitslosenversicherung (SGB III). Voraussetzung ist eine Anwartschaftszeit von in der Regel zw\xf6lf Versicherungsmonaten. Die H\xf6he betr\xe4gt 60 % (mit Kind 67 %) des pauschalierten Nettoentgelts, die Dauer richtet sich nach Alter und Versicherungszeit.")
B.R1=new A.cL("B\xfcrgergeld: Grundsicherung",'Das B\xfcrgergeld (SGB II, fr\xfcher \u201eALG 2"/Hartz IV) sichert den Lebensunterhalt unabh\xe4ngig von fr\xfcherer Besch\xe4ftigung. Es ist bed\xfcrftigkeitsabh\xe4ngig \u2013 Einkommen und Verm\xf6gen der Bedarfsgemeinschaft werden gepr\xfcft.')
B.R6=new A.cL("Der \xdcbergang","Wer keinen oder keinen ausreichenden ALG-1-Anspruch hat oder dessen Anspruch ausl\xe4uft, kann erg\xe4nzend oder anschlie\xdfend B\xfcrgergeld beziehen.")
B.aMX=s([B.QE,B.R1,B.R6],t.aX)
B.aO1=s(["\xa7 149 SGB III","\xa7 147 SGB III","SGB II"],t.s)
B.Ra=new A.hH(B.kh,"ALG 1 oder B\xfcrgergeld (ALG 2)?","Versicherungsleistung gegen Grundsicherung \u2013 die wichtigsten Unterschiede.",B.aMX,B.aO1)
B.R2=new A.cL("Ab dem ersten Tag","Die Arbeitslosmeldung erfolgt pers\xf6nlich oder online mit Wirkung ab dem ersten Tag der Besch\xe4ftigungslosigkeit. Der Antrag auf Arbeitslosengeld kann online gestellt werden.")
B.QY=new A.cL("Wichtige Unterlagen","Der Arbeitgeber \xfcbermittelt der Agentur eine Arbeitsbescheinigung (\xa7 312 SGB III). Hilfreich sind au\xdferdem der K\xfcndigungs- bzw. Aufhebungsvertrag und Nachweise \xfcber Vorbesch\xe4ftigungen.")
B.QO=new A.cL("Krankenversicherung nicht vergessen","Mit dem ALG-Bezug besteht in der Regel Versicherungsschutz. In einer L\xfccke zwischen Job und Leistung sollte der Krankenversicherungsschutz aktiv gekl\xe4rt werden.")
